PRAGMA foreign_keys = 1;
BEGIN TRANSACTION;
ALTER TABLE segments ADD COLUMN number INTEGER;
UPDATE segments SET number = 1 WHERE name == 'PB2';
UPDATE segments SET number = 2 WHERE name == 'PB1';
UPDATE segments SET number = 3 WHERE name == 'PA';
UPDATE segments SET number = 4 WHERE name == 'HA';
UPDATE segments SET number = 5 WHERE name == 'NP';
UPDATE segments SET number = 6 WHERE name == 'NA';
UPDATE segments SET number = 7 WHERE name == 'NS';
UPDATE segments SET number = 8 WHERE name == 'MP';
ALTER TABLE 'references' ADD COLUMN sequence_id TEXT;
UPDATE 'references' SET sequence_id = 'EPI2414998' WHERE name == 'PB2';
UPDATE 'references' SET sequence_id = 'EPI2414999' WHERE name == 'PB1';
UPDATE 'references' SET sequence_id = 'EPI2414997' WHERE name == 'PA';
UPDATE 'references' SET sequence_id = 'EPI2415001' WHERE name == 'HA';
UPDATE 'references' SET sequence_id = 'EPI2415015' WHERE name == 'NP';
UPDATE 'references' SET sequence_id = 'EPI2415000' WHERE name == 'NA';
UPDATE 'references' SET sequence_id = 'EPI2414996' WHERE name == 'MP';
UPDATE 'references' SET sequence_id = 'EPI2414995' WHERE name == 'NS';
DROP VIEW markers_summary;
DELETE FROM mutations WHERE name = 'NA-5:D199G';
UPDATE "references" SET name = "H5" WHERE name = "HA";
UPDATE "references" SET name = "N1" WHERE name = "NA";
UPDATE "references" SET name = "NS allele A" WHERE name = "NS";
UPDATE mutations SET name = replace(name, 'HA1-5', 'HA1');
UPDATE mutations SET name = replace(name, 'HA2-5', 'HA2');
UPDATE mutations SET name = replace(name, 'NA-1', 'NA');
UPDATE mutations SET name = replace(name, 'NS-1', 'NS1');
UPDATE mutations SET name = replace(name, 'NS-2', 'NS2');
UPDATE proteins SET name = 'NS1' WHERE name = 'NS-1';
UPDATE proteins SET name = 'NS2' WHERE name = 'NS-2';
UPDATE OR REPLACE mutations SET name = substr(name, 1, instr(name, ':')) || substr(name, instr(name, ':') + 2);
UPDATE OR IGNORE mutations SET name = substr(name, 1, 4) || (SELECT position FROM mutation_mappings WHERE mutation_name == name AND reference_name == 'H3') || substr(name, length(name)) || '_tmp' WHERE name like 'HA%';
UPDATE mutations SET name = replace(name, '_tmp', '');
UPDATE mutations SET name = 'HA1:129V (H5 numbering)' WHERE name == 'HA1:129V';
ALTER TABLE mutations ADD COLUMN default_position INTEGER;
UPDATE mutations SET default_position = substr(name, instr(name, ':') + 1, length(name) - instr(name, ':') - 1);
UPDATE mutations SET default_position = 129 WHERE name == 'HA1:129V (H5 numbering)';
UPDATE db_version SET major = 7;
UPDATE db_version SET minor = 0;
UPDATE db_version SET date = '2025-07-23';
COMMIT;
